        assertNotNull(user.status(), "Status do usuário não deve ser nulo");
        assertFalse(user.status().isEmpty(), "Status do usuário não deve ser vazio");
    }

    @Test
    @DisplayName("getById retorna Optional.empty quando usuário não existe")
